/**
 * @munesoft/envx — TypeScript Definitions
 */

// ─── Schema Rule ─────────────────────────────────────────────────────────────

export type EnvType = "string" | "number" | "boolean" | "url" | "email" | "json";

export interface SchemaRule<T = any> {
  /** The expected type. Defaults to "string". */
  type?: EnvType;

  /** If true, envx will exit with an error if this variable is missing. */
  required?: boolean;

  /**
   * Default value used when the variable is absent.
   * Can be a static value or a computed expression.
   */
  default?: T;

  /**
   * Restrict the value to a fixed set of allowed values.
   * Checked after type coercion.
   */
  enum?: T[];

  /**
   * Custom validator function.
   * Return false (or throw) to indicate failure.
   */
  validate?: (value: T) => boolean | void;
}

// ─── Schema Map ───────────────────────────────────────────────────────────────

export type Schema = Record<string, SchemaRule>;

// ─── Config File Format ───────────────────────────────────────────────────────

/**
 * Shape of envx.config.js (flat format).
 *
 * @example
 * export default {
 *   PORT: { type: "number", default: 3000 },
 *   API_KEY: { type: "string", required: true },
 * };
 */
export type FlatConfig = Schema & { strict?: boolean };

/**
 * Shape of envx.config.js (structured format).
 *
 * @example
 * export default {
 *   strict: true,
 *   schema: {
 *     PORT: { type: "number", default: 3000 },
 *   },
 * };
 */
export interface StructuredConfig {
  strict?: boolean;
  schema: Schema;
}

export type EnvxConfig = FlatConfig | StructuredConfig;

// ─── Loader Options ───────────────────────────────────────────────────────────

export interface LoadOptions {
  /** Path to the .env file. Defaults to process.cwd()/.env */
  path?: string;

  /**
   * If true, values from .env override existing process.env values.
   * Defaults to false (process.env takes precedence).
   */
  override?: boolean;

  /** Inline schema (skips loading envx.config.js). */
  schema?: Schema;

  /**
   * If true, disallow variables not listed in the schema.
   * Only applies when a schema is provided.
   */
  strict?: boolean;

  /**
   * Print resolved values to stdout after loading.
   * Secrets (keys containing KEY, TOKEN, PASSWORD, SECRET) are masked.
   * Also enabled by ENVX_DEBUG=true in the environment.
   */
  debug?: boolean;

  /**
   * Suppress warnings (e.g. config file load failures).
   * Defaults to false.
   */
  silent?: boolean;
}

// ─── Coerce Result ────────────────────────────────────────────────────────────

export interface CoerceResult<T = any> {
  value: T | undefined;
  error: string | null;
}

// ─── Validate Result ──────────────────────────────────────────────────────────

export interface ValidateResult {
  result: Record<string, any>;
  errors: string[];
}

// ─── Main API ─────────────────────────────────────────────────────────────────

/**
 * Load, validate, and apply environment variables.
 *
 * @example
 * import envx from "@munesoft/envx";
 * await envx({ schema: { PORT: { type: "number", default: 3000 } } });
 */
export default function envx(options?: LoadOptions): Promise<Record<string, any>>;

export { load } from "./src/loader.js";
export { parse, loadFile } from "./src/parser.js";
export { validate } from "./src/validator.js";
export { coerce } from "./src/coerce.js";
export { loadConfig } from "./src/configLoader.js";

// ─── process.env augmentation ────────────────────────────────────────────────

declare global {
  namespace NodeJS {
    interface ProcessEnv {
      [key: string]: string | undefined;
      ENVX_DEBUG?: string;
      NODE_ENV?: "development" | "production" | "test";
    }
  }
}
